import React, { useState } from 'react';
import { Collapse, Navbar, NavbarBrand, NavbarToggler, NavItem, NavLink } from 'reactstrap';
import { Link } from 'react-router-dom';
import styled from 'styled-components';
import navLinks from '../../data/navigation';

const Header = styled.div`
    @media print{
        display:none;
    }
`;

export const NavMenu = ({ className }) => {
    const [collapsed, setCollapsed] = useState(true);
    const toggleNavbar = () => setCollapsed(prev => !prev);

    return (
        <Header className={className}>
            <Navbar className="navbar-expand-sm navbar-toggleable-sm ng-white mb-3" light>
                <NavbarBrand tag={Link} to="/">
                    <img src="initials.svg" height="40px" alt="BM" />
                </NavbarBrand>
                <NavbarToggler onClick={toggleNavbar} className="mr-2" />
                <Collapse className="d-sm-inline-flex flex-sm-row-reverse" isOpen={!collapsed} navbar>
                    <ul className="navbar-nav flex-grow">
                        {navLinks.map(link => (
                            <NavItem key={link.path}>
                                <NavLink tag={Link} className="text-dark" to={link.path}>{link.label}</NavLink>
                            </NavItem>
                        ))}
                    </ul>
                </Collapse>
            </Navbar>
        </Header>
    );
};
